/**
 * @fileoverview ViewTimeline constants — CSS classes, presets, defaults.
 * @module module/ViewTimeline/constants
 */
import { defineParts } from '../shared/definePart.js';


// ── CSS Classes ──────────────────────────────
export const CLS = Object.freeze({
    ELEMENT: 'vt-element',
    VISIBLE: 'vt-visible',
    FULL:    'vt-full',
});

// ── CSS Custom Property ──────────────────────
export const CSS_VAR_PROGRESS = '--vt';

// ── Progress thresholds ──────────────────────
export const PROGRESS_EPSILON = 0.0005;
export const PROGRESS_DIGITS  = 4;

// ── Once-mode reveal animation duration (ms) ─
export const REVEAL_DURATION = 400;

// ── Default config ───────────────────────────
export const DEFAULTS = Object.freeze({
    range:  'entry',
    easing: 'ease-out',
    once:   true,
    offset: 0,
});
/** Semantic part names for pre-render styling overrides. */
export const PART = defineParts('ViewTimeline', {
    ELEMENT     : { class: 'vt-element', aliases: ['element', 'root'] },
});

PART.ELEMENT.jit  = '[backface-visibility:hidden] [-webkit-backface-visibility:hidden]';

// ── Animation presets ────────────────────────
export const PRESETS = Object.freeze({
    'fade-up':    { from: { opacity: 0, y: 40 },   to: { opacity: 1, y: 0 } },
    'fade-down':  { from: { opacity: 0, y: -40 },  to: { opacity: 1, y: 0 } },
    'fade-left':  { from: { opacity: 0, x: 60 },   to: { opacity: 1, x: 0 } },
    'fade-right': { from: { opacity: 0, x: -60 },  to: { opacity: 1, x: 0 } },
    'zoom-in':    { from: { opacity: 0, scale: 0.8 },  to: { opacity: 1, scale: 1 } },
    'zoom-out':   { from: { opacity: 0, scale: 1.2 },  to: { opacity: 1, scale: 1 } },
    'slide-up':   { from: { y: 60 },  to: { y: 0 } },
    'slide-down': { from: { y: -60 }, to: { y: 0 } },
    'blur-in':    { from: { opacity: 0, blur: 10 }, to: { opacity: 1, blur: 0 } },
    'flip-up':    { from: { opacity: 0, rotateX: 15, y: 30 }, to: { opacity: 1, rotateX: 0, y: 0 } },
    'flip-left':  { from: { opacity: 0, rotateY: -15, x: 40 }, to: { opacity: 1, rotateY: 0, x: 0 } },
});