/**
 * @fileoverview ViewTimeline events — global scroll / resize listeners.
 *
 * Installs a pair of passive listeners (once) that drive the rAF-throttled
 * tick loop shared by all ViewTimeline instances.
 *
 * @module module/ViewTimeline/events
 */

import razyui from '../../index.js';

/** @type {boolean} Whether the global listeners have been installed */
let bound = false;

/**
 * Install global scroll + resize listeners (idempotent).
 *
 * Uses rAF-throttling so the tick callback fires at most once per frame
 * regardless of how many scroll/resize events arrive.
 *
 * @param {function} tickFn — callback invoked on each animation frame
 */
export function initGlobalListeners(tickFn) {
    if (bound) return;
    bound = true;

    let ticking = false;

    const onScroll = () => {
        if (!ticking) {
            ticking = true;
            requestAnimationFrame(() => {
                tickFn();
                ticking = false;
            });
        }
    };

    const $window = razyui(window);

    $window.on('scroll', onScroll, { passive: true });
    $window.on('resize', onScroll, { passive: true });
}
