/**
 * @fileoverview ViewTimeline helpers — pure utility functions.
 *
 * No side effects; these receive data and return values.
 *
 * @module module/ViewTimeline/helpers
 */

import { PRESETS } from './constants.js';

/**
 * Build animation config object from user-supplied preset / from-to / keyframes.
 *
 * @param {object} cfg — merged user config
 * @returns {object|null} config suitable for razyui.animate(), or null
 */
export function buildAnimConfig(cfg) {
    // Preset → from/to
    if (cfg.preset && PRESETS[cfg.preset]) {
        const p = PRESETS[cfg.preset];
        return { from: p.from, to: p.to, easing: cfg.easing };
    }

    // from / to shorthand
    if (cfg.from && cfg.to) {
        return { from: cfg.from, to: cfg.to, easing: cfg.easing };
    }

    // Multi-step keyframes
    if (cfg.keyframes) {
        return { keyframes: cfg.keyframes, easing: cfg.easing };
    }

    return null;
}

/**
 * Calculate scroll-driven progress (0→1) based on the element's
 * position relative to the viewport and the configured range.
 *
 * @param {Element}  el     — tracked element
 * @param {object}   config — { range, offset }
 * @param {function} clamp  — clamp(value, min, max)
 * @returns {number} 0..1
 */
export function calcProgress(el, config, clamp) {
    const rect     = el.getBoundingClientRect();
    const vpH      = window.innerHeight;
    // _scrollOffset shifts this element's start point in scroll space
    const elTop    = rect.top + (config.offset || 0) + (config._scrollOffset || 0);
    const elBottom = elTop + rect.height;
    const elH      = rect.height || 1; // guard zero-height
    const range    = config.range;

    // _scrollTotalStagger compresses the travel distance so all
    // staggered elements finish within the original scroll area.
    const compress = config._scrollTotalStagger || 0;

    let raw;

    switch (range) {
        case 'entry':
            // 0 = element top at viewport bottom
            // 1 = element top at 25% from viewport top
            // Uses at least 75% of viewport as travel distance
            raw = (vpH - elTop) / Math.max(Math.max(elH, vpH * 0.75) - compress, elH);
            break;

        case 'exit':
            // 0 = element bottom at viewport bottom
            // 1 = element bottom above viewport top
            raw = -elBottom / Math.max(Math.max(elH, vpH * 0.5) - compress, elH);
            break;

        case 'contain':
            // 0 = element just became fully visible
            // 1 = element about to start leaving
            if (elH >= vpH) {
                const travel = Math.max((elH > vpH ? elH - vpH : 0) - compress, 1);
                raw = elH > vpH ? -elTop / travel : 0.5;
            } else {
                const travel = Math.max(vpH - elH - compress, 1);
                raw = (vpH - elH - elTop) / travel;
            }
            break;

        case 'cover':
        default:
            // 0 = element top at viewport bottom (entering)
            // 1 = element bottom at viewport top (fully past)
            raw = (vpH - elTop) / Math.max(vpH + elH - compress, elH);
            break;
    }

    return clamp(raw, 0, 1);
}
