/**
 * @fileoverview ViewTimeline view — DOM setup / teardown + progress effects.
 *
 * All functions that mutate the DOM live here: setting CSS custom properties,
 * toggling visibility classes, and cleaning up on destroy.
 *
 * @module module/ViewTimeline/view
 */

import razyui from '../../index.js';
import { CLS, CSS_VAR_PROGRESS, PROGRESS_DIGITS, PART } from './constants.js';

/**
 * Apply scroll progress to a tracked element.
 *
 * Sets the `--vt` CSS custom property and toggles visibility / full classes.
 *
 * @param {Element} el       — target element
 * @param {number}  progress — 0..1
 * @param {object}  anim     — razyui.animate() controller
 */
export function applyProgress(el, progress, anim) {
    const $el = razyui(el);

    // Set CSS custom property
    $el.css(CSS_VAR_PROGRESS, progress.toFixed(PROGRESS_DIGITS));

    // Delegate interpolation + apply to animate controller
    anim.at(progress);

    // Toggle class for progress milestones
    $el.toggleClass(CLS.VISIBLE, progress > 0)
       .toggleClass(CLS.FULL, progress >= 1);
}

/**
 * Remove all ViewTimeline DOM artifacts from an element.
 *
 * @param {Element} el   — target element (may be null)
 * @param {object}  anim — razyui.animate() controller (may be null)
 */
export function cleanupElement(el, anim) {
    if (anim) anim.destroy();
    if (el) {
        razyui(el).css(CSS_VAR_PROGRESS, '')
                  .removeClass(CLS.ELEMENT)
                  .removeClass(CLS.VISIBLE)
                  .removeClass(CLS.FULL);
        PART.ELEMENT.unapply(el);
    }
}
